// AdminServiceServer is the server API for AdminService service.
// All implementations must embed UnimplementedAdminServiceServer
// for forward compatibility.
//
// ===========================================================================
// AdminService — управление доменами, ящиками, очередью (скоуп admin).
// ===========================================================================
type AdminServiceServer interface {
	// --- Домены ---
	// Добавляет домен, генерирует DKIM-ключ, возвращает DNS-записи для прописывания.
	AddDomain(context.Context, *AddDomainRequest) (*AddDomainResponse, error)
	ListDomains(context.Context, *ListDomainsRequest) (*ListDomainsResponse, error)
	SetDomainActive(context.Context, *SetDomainActiveRequest) (*SetDomainActiveResponse, error)
	// DNS-записи домена + актуальный статус их проверки.
	GetDomainDNSRecords(context.Context, *GetDomainDNSRecordsRequest) (*GetDomainDNSRecordsResponse, error)
	// Сервер сам резолвит DNS и сверяет MX/SPF/DKIM/DMARC.
	VerifyDomainDNS(context.Context, *VerifyDomainDNSRequest) (*VerifyDomainDNSResponse, error)
	// Новый DKIM-ключ с новым селектором; старый остаётся до retire (двойной период).
	RotateDKIMKey(context.Context, *RotateDKIMKeyRequest) (*RotateDKIMKeyResponse, error)
	// --- Ящики и алиасы ---
	CreateMailbox(context.Context, *CreateMailboxRequest) (*CreateMailboxResponse, error)
	ListMailboxes(context.Context, *ListMailboxesRequest) (*ListMailboxesResponse, error)
	SetMailboxPassword(context.Context, *SetMailboxPasswordRequest) (*SetMailboxPasswordResponse, error)
	SetMailboxActive(context.Context, *SetMailboxActiveRequest) (*SetMailboxActiveResponse, error)
	CreateAlias(context.Context, *CreateAliasRequest) (*CreateAliasResponse, error)
	DeleteAlias(context.Context, *DeleteAliasRequest) (*DeleteAliasResponse, error)
	// --- Очередь отправки ---
	ListQueue(context.Context, *ListQueueRequest) (*ListQueueResponse, error)
	RetryQueueItem(context.Context, *RetryQueueItemRequest) (*RetryQueueItemResponse, error)
	CancelQueueItem(context.Context, *CancelQueueItemRequest) (*CancelQueueItemResponse, error)
	// --- Подавление (bounce-список) ---
	ListSuppressions(context.Context, *ListSuppressionsRequest) (*ListSuppressionsResponse, error)
	RemoveSuppression(context.Context, *RemoveSuppressionRequest) (*RemoveSuppressionResponse, error)
	// --- Статистика отправки ---
	GetStats(context.Context, *GetStatsRequest) (*GetStatsResponse, error)
	mustEmbedUnimplementedAdminServiceServer()
}

